const XLSX = require('xlsx');

// READ FROM LOCAL FILE - update this path to where your Excel is
const filePath = 'C:\\Users\\rathn\\OneDrive\\Pictures\\new ganesh\\Ganesh-resedence\\EasyStay_Target_Leads_v2.xlsx';

try {
  const wb = XLSX.readFile(filePath);
  const ws = wb.Sheets['Target Leads'];
  const leads = XLSX.utils.sheet_to_json(ws);

  // Return all leads as n8n items
  return leads.map(lead => ({ json: lead }));
} catch(e) {
  throw new Error('Could not read Excel file at: ' + filePath + '. Error: ' + e.message);
}

const config = $('Config').first().json;
const stage = config.stage;
const items = $input.all();

// Filter based on stage and contact status
const eligible = items.filter(item => {
  const lead = item.json;
  const phone = lead['WhatsApp Number'];
  if (!phone) return false;

  const status = (lead['Contact Status'] || '').toUpperCase();

  // Stage-based filtering
  if (stage === 'day1') return status === 'NOT CONTACTED';
  if (stage === 'day2') return status === 'DAY 1 SENT';
  if (stage === 'day5') return status === 'DAY 2 SENT';
  if (stage === 'day10') return status === 'DAY 5 SENT';
  if (stage === 'day20') return status === 'DAY 10 SENT';

  return false;
});

// Sort by priority: ULTRA_HOT first
const order = { 'ULTRA_HOT': 0, 'HOT': 1, 'WARM': 2, 'COLD': 3 };
eligible.sort((a, b) => (order[a.json['Lead Priority']] || 2) - (order[b.json['Lead Priority']] || 2));

// Limit to max per run
const max = config.max_messages_per_run || 15;
const batch = eligible.slice(0, max);

console.log(`Stage: ${stage} | Eligible: ${eligible.length} | Batch: ${batch.length}`);

if (batch.length === 0) {
  return [{ json: { _empty: true, message: 'No eligible leads for stage: ' + stage } }];
}

return batch;

const lead = $json;
let phone = (lead['WhatsApp Number'] || '').replace(/[^0-9]/g, '');
if (phone.startsWith('0')) phone = '91' + phone.substring(1);
if (!phone.startsWith('91') && phone.length === 10) phone = '91' + phone;

const config = $('Config').first().json;
const stage = config.stage;

// Pick the right message column based on stage
const colMap = {
  day1: 'Cold Message (Day 1)',
  day2: 'Follow-up (Day 2)',
  day5: 'Follow-up (Day 5)',
  day10: 'Follow-up (Day 10)',
  day20: 'Follow-up (Day 20)'
};

const message = lead[colMap[stage]] || lead['Cold Message (Day 1)'] || '';

return [{
  json: {
    clean_phone: phone,
    property_name: lead['Property Name'],
    lead_priority: lead['Lead Priority'],
    message: message,
    stage: stage,
    original_phone: lead['WhatsApp Number'],
    google_maps: lead['Google Maps Link'],
    rating: lead['Google Rating'],
    pain_points: lead['Pain Points']
  }
}];

// Check if the response indicates the number is on WhatsApp
const response = $input.first().json;
const preparedData = $('Prepare Lead Data').first().json;

let isOnWhatsApp = false;
let jid = '';

if (Array.isArray(response)) {
  const found = response.find(r => r.exists === true);
  if (found) {
    isOnWhatsApp = true;
    jid = found.jid || '';
  }
} else if (response && Array.isArray(response.data)) {
  const found = response.data.find(r => r.exists === true);
  if (found) {
    isOnWhatsApp = true;
    jid = found.jid || '';
  }
}

return [{
  json: {
    ...preparedData,
    is_on_whatsapp: isOnWhatsApp,
    whatsapp_jid: jid
  }
}];

const sendResult = $input.first().json;
const leadData = $('Parse WhatsApp Check').first().json;

const success = !!(sendResult?.key?.id);

return [{
  json: {
    status: success ? 'SENT ✅' : 'FAILED ❌',
    property: leadData.property_name,
    phone: leadData.clean_phone,
    priority: leadData.lead_priority,
    stage: leadData.stage,
    message_id: sendResult?.key?.id || 'none',
    sent_at: new Date().toISOString(),
    error: success ? '' : JSON.stringify(sendResult)
  }
}];

const leadData = $('Parse WhatsApp Check').first().json;

return [{
  json: {
    status: 'SKIPPED - NOT ON WHATSAPP ❌',
    property: leadData.property_name,
    phone: leadData.clean_phone,
    priority: leadData.lead_priority,
    skipped_at: new Date().toISOString()
  }
}];

// No eligible leads for this stage
return [{
  json: {
    status: 'NO LEADS',
    message: $json.message || 'No eligible leads found for the current stage. Update Contact Status in Excel and try again.'
  }
}];
